import { createSetting } from '@shopex/finder'
import { Message, MessageBox } from 'element-ui'
export default (vm) => {
  const formatDate = (timestamp) => {
    var date = new Date(timestamp * 1000) //時間戳為10位需*1000，時間戳為13位的話不需乘1000
    var YY = date.getFullYear() + '-'
    var MM = (date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1) + '-'
    var DD = date.getDate() < 10 ? '0' + date.getDate() : date.getDate()
    var hh = (date.getHours() < 10 ? '0' + date.getHours() : date.getHours()) + ':'
    var mm = (date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes()) + ':'
    var ss = date.getSeconds() < 10 ? '0' + date.getSeconds() : date.getSeconds()
    return YY + MM + DD + ' ' + hh + mm + ss
  }
  const formatStatus = (val) => {
    if (val == 'pending') {
      return '提現處理中'
    } else if (val == 'succeeded') {
      return '提現成功'
    } else if (val == 'failed') {
      return '提現失敗'
    }
  }
  const formatMoney = (money) => {
    return (money / 100).toFixed(2).toLocaleString()
  }
  return createSetting({
    columns: [
      { name: '提現日期', key: 'create_time', width: 150, formatter: formatDate },
      { name: '提現帳戶', key: 'user_name', width: 150 },
      { name: '提現卡號', key: 'bank_card', width: 150 },
      { name: '提現類型', key: 'cash_type', width: 150 },
      { name: '提現狀態', key: 'status', width: 150, formatter: formatStatus },
      { name: '提現金額', key: 'cash_amt', width: 150, formatter: formatMoney },
      { name: '備注', key: 'remark' }
    ]
  })
}
